-- PostgreSQL dump converted from MySQL backup for Praiastur Inventário
BEGIN;
DROP TABLE IF EXISTS historico_movimentacoes CASCADE;
DROP TABLE IF EXISTS itens_operacionais CASCADE;
DROP TABLE IF EXISTS saida_itens CASCADE;
DROP TABLE IF EXISTS saidas_administrativas CASCADE;
DROP TABLE IF EXISTS entradas_administrativas CASCADE;
DROP TABLE IF EXISTS apartamentos CASCADE;
DROP TABLE IF EXISTS residenciais CASCADE;
DROP TABLE IF EXISTS produtos_administrativos CASCADE;
DROP TABLE IF EXISTS usuarios CASCADE;
DROP TYPE IF EXISTS perfil_usuario CASCADE;
DROP TYPE IF EXISTS status_item_operacional CASCADE;
DROP TYPE IF EXISTS status_saida CASCADE;
CREATE TYPE perfil_usuario AS ENUM ('ADMINISTRADOR','OPERACIONAL');
CREATE TYPE status_item_operacional AS ENUM ('BOM','ATENCAO','PROBLEMA','EM_FALTA');
CREATE TYPE status_saida AS ENUM ('FINALIZADA','CANCELADA');

CREATE TABLE IF NOT EXISTS usuarios (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nome VARCHAR(150) NOT NULL,
  email VARCHAR(150) NOT NULL UNIQUE,
  senha VARCHAR(255) NOT NULL,
  perfil perfil_usuario NOT NULL DEFAULT 'OPERACIONAL',
  status BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMP NOT NULL,
  updated_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS produtos_administrativos (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nome VARCHAR(150) NOT NULL,
  quantidade_atual INTEGER NOT NULL DEFAULT 0,
  estoque_minimo INTEGER NOT NULL DEFAULT 0,
  observacao TEXT,
  status BOOLEAN NOT NULL DEFAULT TRUE,
  created_by INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL,
  updated_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS residenciais (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nome VARCHAR(150) NOT NULL,
  cidade VARCHAR(100) NOT NULL,
  estado VARCHAR(2) NOT NULL,
  endereco VARCHAR(255),
  observacao TEXT,
  imagem VARCHAR(255),
  status BOOLEAN NOT NULL DEFAULT TRUE,
  created_by INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL,
  updated_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS apartamentos (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  residencial_id INTEGER NOT NULL REFERENCES residenciais(id) ON DELETE CASCADE ON UPDATE CASCADE,
  nome_numero VARCHAR(100) NOT NULL,
  tipo VARCHAR(50),
  observacao TEXT,
  imagem VARCHAR(255),
  status BOOLEAN NOT NULL DEFAULT TRUE,
  created_by INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL,
  updated_at TIMESTAMP NOT NULL,
  CONSTRAINT apartamentos_residencial_id_nome_numero UNIQUE (residencial_id, nome_numero)
);

CREATE TABLE IF NOT EXISTS entradas_administrativas (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  produto_id INTEGER NOT NULL REFERENCES produtos_administrativos(id) ON DELETE CASCADE ON UPDATE CASCADE,
  quantidade INTEGER NOT NULL,
  observacao TEXT,
  usuario_id INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS saidas_administrativas (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  codigo_saida VARCHAR(30) NOT NULL UNIQUE,
  destinatario VARCHAR(150) NOT NULL,
  observacao TEXT,
  status status_saida NOT NULL DEFAULT 'FINALIZADA',
  usuario_id INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS saida_itens (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  saida_id INTEGER NOT NULL REFERENCES saidas_administrativas(id) ON DELETE CASCADE ON UPDATE CASCADE,
  produto_id INTEGER NOT NULL REFERENCES produtos_administrativos(id) ON DELETE CASCADE ON UPDATE CASCADE,
  quantidade INTEGER NOT NULL
);

CREATE TABLE IF NOT EXISTS itens_operacionais (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  apartamento_id INTEGER NOT NULL REFERENCES apartamentos(id) ON DELETE CASCADE ON UPDATE CASCADE,
  nome VARCHAR(150) NOT NULL,
  categoria VARCHAR(80),
  quantidade INTEGER NOT NULL DEFAULT 1,
  status_item status_item_operacional NOT NULL DEFAULT 'BOM',
  observacao TEXT,
  imagem VARCHAR(255),
  updated_by INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  created_at TIMESTAMP NOT NULL,
  updated_at TIMESTAMP NOT NULL
);

CREATE TABLE IF NOT EXISTS historico_movimentacoes (
  id INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  usuario_id INTEGER REFERENCES usuarios(id) ON DELETE SET NULL ON UPDATE CASCADE,
  modulo VARCHAR(50) NOT NULL,
  acao VARCHAR(50) NOT NULL,
  tabela_referenciada VARCHAR(100),
  registro_id INTEGER,
  descricao TEXT,
  created_at TIMESTAMP NOT NULL
);

-- Data for usuarios

-- Data for residenciais

