-- Data for historico_movimentacoes
SELECT setval(pg_get_serial_sequence('usuarios', 'id'), COALESCE((SELECT MAX(id) FROM usuarios), 1));
SELECT setval(pg_get_serial_sequence('produtos_administrativos', 'id'), COALESCE((SELECT MAX(id) FROM produtos_administrativos), 1));
SELECT setval(pg_get_serial_sequence('residenciais', 'id'), COALESCE((SELECT MAX(id) FROM residenciais), 1));
SELECT setval(pg_get_serial_sequence('apartamentos', 'id'), COALESCE((SELECT MAX(id) FROM apartamentos), 1));
SELECT setval(pg_get_serial_sequence('entradas_administrativas', 'id'), COALESCE((SELECT MAX(id) FROM entradas_administrativas), 1));
SELECT setval(pg_get_serial_sequence('saidas_administrativas', 'id'), COALESCE((SELECT MAX(id) FROM saidas_administrativas), 1));
SELECT setval(pg_get_serial_sequence('saida_itens', 'id'), COALESCE((SELECT MAX(id) FROM saida_itens), 1));
SELECT setval(pg_get_serial_sequence('itens_operacionais', 'id'), COALESCE((SELECT MAX(id) FROM itens_operacionais), 1));
SELECT setval(pg_get_serial_sequence('historico_movimentacoes', 'id'), COALESCE((SELECT MAX(id) FROM historico_movimentacoes), 1));
COMMIT;